+        assert_eq!(
+            infer_event_type_from_commit(1, "mark in progress"),
+            "claimed"
+        );
+        // "exclaim" should NOT trigger "claimed"
+        assert_eq!(
+            infer_event_type_from_commit(1, "exclaim about progress"),
